#include <iostream>
#include <fstream>
#include <queue>
#include <vector>
#include <cstring>

using namespace std;
/*
    sol -> combination that gets the maximum consecutive numbers
    x   -> a generated combination
    mx  -> maximum consecutive numbers obtainable
*/
int k, n, t, x[11], sol[11], mx;

void check() {
    int i, j, i1;
    /*
        sums[i] = 1, if i can be obtained by adding numbers from x, maximum t
                     times
                = 0, otherwise
        apps[i] = number of additions made to get i as sum
    */
    int sums[1001], apps[1001];
    memset(sums, 0, sizeof(sums));
    memset(apps, 0, sizeof(apps));

    // 0 is obtainable, in order to be able to generate all sums
    sums[0] = 1;

    // mark the apps of every number as t + 1 (impossible value)
    for (i1 = 1; i1 <= x[n] * t; i1++)
        apps[i1] = t + 1;

    // For every number from 0 to maximum obtainable value x[n] * t
    // (x[n] - maximum number, and we can make t additions
    // Try to add a number from the combination (from x[1] to x[n]), only to
    // the already obtained sums
    // Do this t times
    for (i = 1; i <= t; i++)
        for (j = 1; j <= n; j++)
            for (i1 = 0; i1 <= x[n] * t; i1++)
                // if the sum was already obtained, and we can make the new sum
                // in fewer steps, update its steps
                if (sums[i1] == 1 && apps[i1 + x[j]] > apps[i1] + 1) {
                    sums[i1 + x[j]] = 1;
                    apps[i1 + x[j]] = apps[i1] + 1;
                }

    // Go through the obtainable sums and compute the maximum lenght of
    // consecutive ones
    int mx_lg = 0, lg = 0;
    for (i = 1; i <= x[n] * t; i++)
        // update the length of current sequence
        if (sums[i] == 1) {
            lg++;
        } else {   // update the maximum
            if (mx_lg < lg)
                mx_lg = lg;
            // restart the sequence
            lg = 0;
        }
    // update the maximum again (for last sequence)
    if (mx_lg < lg)
        mx_lg = lg;
    // update the global maximum and solution
    if (mx < mx_lg) {
        mx = mx_lg;
        for (i = 1; i <= n; i++)
            sol[i] = x[i];
    }
}

// generate the combination of n dimensions from 1 to k
void bkt(int pas) {
    int i;
    // first one is always 1 (hint from problem's statement)
    if (pas == 1) {
        x[pas] = 1;
        bkt(pas + 1);
    } else {
        // try all values from last + 1, in order to not have any equal values
        // generated
        for (i = x[pas - 1] + 1; i <= k; i++) {
            x[pas] = i;
            // if terms can be added
            if (pas < n)
                bkt(pas + 1);
            // otherwise, get the number of consecutive obtainable numbers
            // from the ones generated
            else
                check();
        }
    }
}
int main() {
    ifstream f("lego.in");
    ofstream g("lego.out");

    f >> k >> n >> t;

    // generate solutions
    bkt(1);

    g << mx << endl;
    for (int i = 1; i <= n; i++)
        g << sol[i] << ' ';

    return 0;
}

import java.io.BufferedReader;
import java.io.BufferedWriter;
import java.io.File;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;
import java.util.ArrayList;
import java.util.List;

public class Lego {

	/**
	 * Se genereaza toate combinatiile de piese, din cele K, selectand doar N elemente.
	 *
	 * @param step elemntul pe care il adaugam in solutie
	 * @param n numarulmaxim de elemente selectate
	 * @param k numarul tottal de piese
	 * @param sol list cu combinarea care se formeaza
	 * @param all retine toate combinarile
	 */
	static void back(int step, int n, int k, List<Integer> sol, List<List<Integer>> all) {
		// se verifica daca s-au selectat N piese si se aduaga in lista de combiari
		if (step == n) {
			all.add(new ArrayList<>(sol));
			return;
		}
		// se parcurg piesele care au o dimensiunea mai mare decat piesa curenta
		int i = step > 0 ? sol.get(step - 1) : 0;
		for (; i < k; i++) {
			sol.add(i + 1);
			back(step + 1, n, k, sol, all);
			sol.remove(sol.size() - 1);
		}
	}

	/**
	 * Se calculeaza numarul minim de piese necesare a carei suma este egala cu o anumita dimensiune
	 *
	 *
	 * @param dp matrice care stocheaza numarul minim de piese pentru a obtine o anumita dimensiune
	 * @param numLine numarul de linii a matricii
	 * @param numCol numarul de coloane a matricii
	 * @param combination combinarea pentru care se calculeaza suma dimensiunilor
	 */
	static void minSumRequired(int[][] dp, int numLine, int numCol, List<Integer> combination) {
		// se completeaza cazul de baza
		for (int i = 1; i < numCol; i++) {
			dp[0][i] = Integer.MAX_VALUE - 1;
		}

		// se parcurg liniile matricii,
		// index-ul unei linii coincide cu index-ul unei piese din lista de combinari
		for (int i = 1; i < numLine; i++) {
			// se parcurg coloanele matricii,
			// index-ul unei coloane reprezinta dimensiunea pentru care se genereaza suma cu
			// numar minim de piese
			for (int j = 1; j < numCol; j++) {
				// piesa curenta este mai mare decat dimensiunea pentru care se calculeaza suma
				if (combination.get(i - 1) > j) {
					// se ia numarul minim de la pasul anterior
					dp[i][j] = dp[i - 1][j];
				} else {
					// se alege numarul minim de piese dintre cel de la pasul anterior si cel de la
					// pasul curent
					dp[i][j] = Math.min(dp[i - 1][j], dp[i][j - combination.get(i - 1)] + 1);
				}
			}
		}
	}

	public static void main(String[] args) throws IOException {
		File input = new File("lego.in");
		BufferedReader reader = new BufferedReader(new FileReader(input));
		String line = reader.readLine();
		String[] values = line.split(" ");
		int K = Integer.parseInt(values[0]);
		int N = Integer.parseInt(values[1]);
		int T = Integer.parseInt(values[2]);
		List<Integer> sol = new ArrayList<>();
		List<List<Integer>> allCombinations = new ArrayList<>(); // sunt stocate toate combinarile
		back(0, N, K, sol, allCombinations);
		int maxConsecutive = -1; // retine numarul maxim de dimensiuni consecutive
		// retine combinarea cu numar maxim de dimensiuni consecutive
		List<Integer> combination = new ArrayList<>();
		// se parcurg toate combinarile care il contin pe 1
		for (List<Integer> it : allCombinations) {
			if (it.get(0) != 1) {
				break;
			}

			// se initializeaza matricea in care sunt stocate numarul minim de elemente necesare
			// a caror suma este egala cu o anumita dimenisune
			int numLine = N + 1;
			int numCol = T * K + 1;
			int[][] dp = new int[numLine][numCol];

			minSumRequired(dp, numLine, numCol, it);

			// contor folosit pentru numararea dimensiunilor consecutive a combinarii curente
			int cnt = 0;
			// numarul maxim de dimensiuni consecutive a combinarii curente
			int totalConsecutive = -1;

			// se parcurg coloanele de pe ultima linie
			for (int i = 1; i < numCol; i++) {
				// se verifica daca pentru dimensiunea curenta, numarul minim de piese este
				// mai mic sua egal decat T
				if (dp[numLine - 1][i] <= T) {
					cnt++; // se incrementeaza contorul
				} else {
					// se verifica daca s-a gasit o secventa mai mare de dimensiuni diferite
					if (totalConsecutive < cnt) {
						totalConsecutive = cnt;
						cnt = 0;
					}
				}
			}

			if (cnt > totalConsecutive) {
				totalConsecutive = cnt;
			}

			// se actualizeaza combinarea cu numarul maxim de dimensiuni diferite
			if (maxConsecutive < totalConsecutive) {
				maxConsecutive = totalConsecutive;
				combination = new ArrayList<>(it);
			}
		}


		File output = new File("lego.out");
		BufferedWriter writer = new BufferedWriter(new FileWriter(output));
		// se scrie numarul maxim de elemente consecutive
		writer.write(String.valueOf(maxConsecutive) + '\n');
		// se scrie combinarea cu numarul maxim de dimensiuni consecutive
		for (Integer value : combination) {
			writer.write(value + " ");
		}
		writer.close();
	}
}
